const items = $input.all();
return items.map(item => {
  const title = item.json.title || 'New Video';
  const link = item.json.link || '';
  const pubDate = item.json.pubDate || new Date().toDateString();

  const tweet = '🎬 New Money Mind video: ' + title + '\n\n' +
    '👉 Watch now: ' + link + '\n\n' +
    '#PersonalFinance #MoneyMind #Investing #FinancialFreedom #WealthBuilding';

  const fbPost = '🎬 NEW VIDEO DROP: ' + title + '\n\n' +
    'Just uploaded a brand new Money Mind video! 💰\n\n' +
    '👉 Watch it here: ' + link + '\n\n' +
    '💡 Like & Subscribe for weekly money strategies!\n\n' +
    '#MoneyMind #PersonalFinance #Investing #FinancialFreedom';

  const newsletterHtml = '<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto">' +
    '<div style="background:#1A237E;padding:20px;text-align:center">' +
    '<h1 style="color:#FFD700;margin:0">Money Mind</h1>' +
    '<p style="color:#fff;margin:5px 0">Learn to Think Like Money</p></div>' +
    '<div style="padding:30px">' +
    '<h2 style="color:#1A237E">🎬 New Video: ' + title + '</h2>' +
    '<p>A new Money Mind video just dropped!</p>' +
    '<p style="text-align:center"><a href="' + link + '" style="background:#1A237E;color:#FFD700;padding:14px 28px;text-decoration:none;border-radius:6px;font-weight:bold;display:inline-block">▶ Watch Now</a></p>' +
    '<p style="color:#666;font-size:13px">Published: ' + pubDate + '</p>' +
    '</div></div>';

  return { json: { title, link, tweet, fbPost, newsletterHtml } };
});
